  // src/browser-entry.ts
  var THEME_STORAGE_KEY = "guess-the-verb-theme";
  (void 0).applyEarlyTheme(THEME_STORAGE_KEY);
  var title = config.title;
  var description = config.description || "";
  var authors = Array.isArray(config.author) ? config.author.join(", ") : config.author;
  var client = new (void 0)({
    storagePrefix: "guess-the-verb-",
    defaultTheme: "dos-classic",
    themes: [
      { id: "dos-classic", name: "DOS Classic" },
      { id: "modern-dark", name: "Modern Dark" },
      { id: "retro-terminal", name: "Retro Terminal" },
      { id: "paper", name: "Paper" }
    ],
    storyInfo: {
      title,
      description,
      authors
    },
    callbacks: {
      getHelpText: () => `Commands are simple sentences like LOOK, TAKE KEY, or PUT BOOK ON TABLE.

Common commands:
  LOOK (L)        Describe surroundings
  INVENTORY (I)   List what you're carrying
  EXAMINE (X)     Look closely at something
  TAKE / DROP     Pick up or put down items
  OPEN / CLOSE    Open or close containers
  GO <direction>  Move (N, S, E, W, U, D)
  SAVE / RESTORE  Save or load your game
  QUIT            Leave the game`,
      getAboutText: () => [title, description, `By ${authors}`].filter(Boolean).join("\n"),
      handleStoryEvent: (event, display) => {
        if (event.type?.includes("blocked") || event.type?.includes("failed")) {
          const data = event.data || {};
          const messageId = data.messageId || data.reason;
          if (messageId) {
            const targetName = data.targetName || data.target || "";
            const action = messageId.replace(/^if\.\w+\./, "").replace(/_/g, " ");
            display.displayText(
              targetName ? `You can't ${action}.` : "You can't do that."
            );
            return true;
          }
        }
        return false;
      }
    }
  });
  async function start() {
    console.log("=== Guess the Verb BROWSER START ===");
    client.initialize({
      statusLocation: document.getElementById("location-name"),
      statusScore: document.getElementById("score-turns"),
      textContent: document.getElementById("text-content"),
      mainWindow: document.getElementById("main-window"),
      commandInput: document.getElementById("command-input"),
      modalOverlay: document.getElementById("modal-overlay"),
      saveDialog: document.getElementById("save-dialog"),
      restoreDialog: document.getElementById("restore-dialog"),
      startupDialog: document.getElementById("startup-dialog"),
      saveNameInput: document.getElementById("save-name-input"),
      saveSlotsListEl: document.getElementById("save-slots-list"),
      restoreSlotsListEl: document.getElementById("restore-slots-list"),
      noSavesMessage: document.getElementById("no-saves-message"),
      startupSaveInfo: document.getElementById("startup-save-info"),
      menuBar: document.getElementById("menu-bar")
    });
    const world = new import_world_model2.WorldModel();
    const player = world.createEntity("player", import_world_model2.EntityType.ACTOR);
    world.setPlayer(player.id);
    const language = new import_lang_en_us.LanguageProvider();
    const parser = new import_parser_en_us.Parser(language);
    if (story.extendParser)
      story.extendParser(parser);
    if (story.extendLanguage)
      story.extendLanguage(language);
    const perceptionService = new import_stdlib.PerceptionService();
    const engine = new import_engine.GameEngine({
      world,
      player,
      parser,
      language,
      perceptionService
    });
    client.connectEngine(engine, world);
    engine.setStory(story);
    engine.registerSaveRestoreHooks(client.getSaveRestoreHooks());
    await client.start();
  }
  if (document.readyState === "loading") {
    document.addEventListener("DOMContentLoaded", start);
  } else {
    start();
  }
